func payBill(amount: Double?) {
    guard let cost = amount else {
        print("Error: No bill amount found.")
        return
    }

    // We are past the bouncer, cost is safe!
    print("Paying $\(cost) now.")
}

payBill(amount: 50.00)
payBill(amount: nil)
